import{_ as e,o as t,c as l,a5 as s}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"概念：故障码与故障日志（fault code and fault log）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：故障码与故障日志（fault code and fault log）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0030-ups-fault-code-logging.html` 的源稿和补充资料。它只使用教学故障码和教学日志字段，不包含公司内部故障码、未公开产品方案、客户项目参数或内部测试数据。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-fault-code-logging.md","filePath":"content/power/concepts/embedded/ups-fault-code-logging.md","lastUpdated":null}'),o={name:"content/power/concepts/embedded/ups-fault-code-logging.md"};function i(n,a,d,p,c,r){return t(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="概念-故障码与故障日志-fault-code-and-fault-log" tabindex="-1">概念：故障码与故障日志（fault code and fault log） <a class="header-anchor" href="#概念-故障码与故障日志-fault-code-and-fault-log" aria-label="Permalink to &quot;概念：故障码与故障日志（fault code and fault log）&quot;">​</a></h1><p>本页是 <code>lessons/0030-ups-fault-code-logging.html</code> 的源稿和补充资料。它只使用教学故障码和教学日志字段，不包含公司内部故障码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>故障码（fault code）是给故障原因分配的可读编号或枚举。故障日志（fault log）是在故障发生时记录一条事件，通常包含时间戳（timestamp）、故障码、触发源（trigger source）、发生时模式和是否锁存。</p><p>本节只讲一个概念：故障闭环之后要留下可调试证据。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>UPS 现场问题常常不是“故障有没有发生”，而是“先发生了什么、谁触发的、当时处于什么模式”。没有故障日志，工程师只能靠用户描述、现象猜测和复现尝试。</p><p>教学日志让你建立阅读路径：故障码说明类别，时间戳说明发生时刻，触发源说明来自哪个模块，模式说明系统当时处于什么状态。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>故障锁存像拉下急停，故障日志像在值班记录本上写一行：什么时候、什么故障、谁报的警、当时设备处于什么运行状态。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if latched_fault rises from 0 to 1:</span></span>
<span class="line"><span>    event.timestamp_ms = now_ms</span></span>
<span class="line"><span>    event.fault_code = detected_fault_code</span></span>
<span class="line"><span>    event.trigger_source = &quot;protection module&quot;</span></span>
<span class="line"><span>    event.mode_when_logged = current_mode</span></span>
<span class="line"><span>    event.latched_fault = 1</span></span></code></pre></div><p>本课只记录单条教学事件，不实现环形缓冲区、Flash 保存或通信上传。</p><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_fault_code_logging.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_fault_code_logging.png</span></span></code></pre></div><p>图中包含保护故障、锁存故障、日志脉冲、故障码和记录时模式。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsFaultCode</code>：教学故障码枚举。</li><li><code>UpsFaultLogEvent</code>：单条日志事件。</li><li><code>UpsFaultLog_Record()</code>：生成故障日志事件。</li><li><code>UpsFaultLog_Print()</code>：把事件打印成可检查证据。</li></ul><p>真实工程还会涉及日志缓存、掉电保存、擦写寿命、通信读取、故障码版本兼容等问题，本节先不展开。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：有故障锁存就不需要日志。<br> 正确理解：锁存告诉你系统停了，日志告诉你为什么停、什么时候停、谁触发。</li><li>错误理解：日志越多越好。<br> 正确理解：嵌入式存储有限，日志要记录关键事件和关键字段。</li><li>错误理解：导师给的真实故障码可以记进学习仓库。<br> 正确理解：不能记录公司内部故障码，只能记录通用组织方式和字段设计思路。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_fault_code_logging.py --no-open</code> 并打开 <code>simulations/results/ups_fault_code_logging.png</code>。</li><li>能解释故障码、时间戳、触发源、模式和锁存字段分别解决什么问题。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>fault_log</code> 输出。</li><li>能基于 <code>fault_log.c -&gt; UpsFaultLog_Record()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>fault_log.c -&gt; UpsFaultLog_Record()</code> 记录时间戳、故障码、触发源和模式。真实工程里故障日志通常还会记录哪些通用字段？</li><li>我用 <code>simulations/results/ups_fault_code_logging.png</code> 看到日志只在锁存时记录一次。真实工程里同一故障重复出现时会覆盖、追加还是计数？</li><li>我不会记录公司内部故障码，只想确认组织方式：真实工程里故障码是否有版本号、分类范围或通信协议映射？</li></ul>`,28)])])}const g=e(o,[["render",i]]);export{h as __pageData,g as default};
